const items = $input.all();
const now = new Date();
const results = [];

for (const item of items) {
  const attrs = item.json.attributes || {};
  const dateParts = (attrs.TERMIN_DATUM || '').split('.');
  const time = (attrs.TERMIN_UHRZEIT || '10:00').split(':');

  if (dateParts.length !== 3) continue;

  const terminDate = new Date(
    parseInt(dateParts[2]), parseInt(dateParts[1]) - 1, parseInt(dateParts[0]),
    parseInt(time[0]), parseInt(time[1])
  );

  const hoursUntil = (terminDate - now) / (1000 * 60 * 60);

  let reminderType = null;
  if (hoursUntil > 23 && hoursUntil <= 25) reminderType = '24h_reminder';
  else if (hoursUntil > 0.5 && hoursUntil <= 1.5) reminderType = '1h_reminder';

  if (reminderType) {
    results.push({
      json: {
        ...item.json,
        reminderType,
        hoursUntil: Math.round(hoursUntil * 10) / 10
      }
    });
  }
}

return results;
